import { Search } from "lucide-react"

interface Props {
  employees: any[]
  search: string
  setSearch: any
  filterRole: string
  setFilterRole: any
}

export default function EmployeeTable({
  employees,
  search,
  setSearch,
  filterRole,
  setFilterRole,
}: Props) {
  const filteredEmployees =
    employees.filter((employee: any) => {
      const matchSearch =
        employee.name
          .toLowerCase()
          .includes(search.toLowerCase()) ||
        employee.email
          .toLowerCase()
          .includes(search.toLowerCase())

      const matchRole =
        filterRole === "all" ||
        employee.role === filterRole

      return matchSearch && matchRole
    })

  return (
    <div className="bg-white rounded-3xl p-8 shadow-sm mb-10">

      <div className="flex items-center justify-between mb-6">

        <h2 className="text-2xl font-bold">
          Employees
        </h2>

        <div className="flex gap-4">

          <div className="relative">

            <Search
              size={18}
              className="absolute left-4 top-4 text-gray-400"
            />

            <input
              placeholder="Search..."
              value={search}
              onChange={(e) =>
                setSearch(e.target.value)
              }
              className="border rounded-xl pl-11 p-3"
            />

          </div>

          <select
            value={filterRole}
            onChange={(e) =>
              setFilterRole(e.target.value)
            }
            className="border rounded-xl p-3"
          >
            <option value="all">
              All
            </option>

            <option value="employee">
              Employee
            </option>

            <option value="hr">
              HR
            </option>

            <option value="admin">
              Admin
            </option>
          </select>

        </div>

      </div>

      <table className="w-full">

        <thead className="bg-gray-100">

          <tr>

            <th className="text-left p-4">
              Name
            </th>

            <th className="text-left p-4">
              Email
            </th>

            <th className="text-left p-4">
              Role
            </th>

          </tr>

        </thead>

        <tbody>

          {filteredEmployees.map(
            (employee: any) => (
              <tr
                key={employee.id}
                className="border-b hover:bg-gray-50"
              >

                <td className="p-4">
                  {employee.name}
                </td>

                <td className="p-4">
                  {employee.email}
                </td>

                <td className="p-4">

                  <span className="bg-black text-white px-4 py-2 rounded-full text-sm">

                    {employee.role}

                  </span>

                </td>

              </tr>
            )
          )}

        </tbody>

      </table>

    </div>
  )
}