interface Props {
  assets: any[]
}

export default function AssetTable({
  assets,
}: Props) {
  return (
    <div className="bg-white rounded-2xl shadow overflow-hidden p-6 mb-10">

      <h2 className="text-2xl font-bold mb-6">
        Asset Inventory
      </h2>

      <table className="w-full">

        <thead className="bg-gray-100">

          <tr>

            <th className="text-left p-4">
              Asset
            </th>

            <th className="text-left p-4">
              Category
            </th>

            <th className="text-left p-4">
              Serial Number
            </th>

            <th className="text-left p-4">
              Status
            </th>

            <th className="text-left p-4">
              Assigned To
            </th>

          </tr>

        </thead>

        <tbody>

          {assets.map((asset: any) => (
            <tr
              key={asset.id}
              className="border-t hover:bg-gray-50"
            >

              <td className="p-4">
                {asset.name}
              </td>

              <td className="p-4">
                {asset.category}
              </td>

              <td className="p-4">
                {asset.serialNumber}
              </td>

              <td className="p-4">

                <span className="bg-green-100 text-green-700 px-4 py-2 rounded-full text-sm font-semibold">

                  {asset.status}

                </span>

              </td>

              <td className="p-4">
                {asset.assignedTo}
              </td>

            </tr>
          ))}

        </tbody>

      </table>

    </div>
  )
}