"use client"

import { useEffect, useState } from "react"
import axios from "axios"
import Cookies from "js-cookie"
import Sidebar from "@/components/Sidebar"
import DashboardCards from "@/components/DashboardCards"
import EmployeeTable from "@/components/EmployeeTable"
import AssetTable from "@/components/AssetTable"
import RequestTable from "@/components/RequestTable"

import {
  Users,
  Shield,
  Briefcase,
  Search,
  Activity,
  Laptop,
} from "lucide-react"


export default function DashboardPage() {
  const [employees, setEmployees] = useState<any[]>([])
  const [logs, setLogs] = useState<any[]>([])
  const [assets, setAssets] = useState<any[]>([])
  const [requests, setRequests] =
    useState<any[]>([])

  const [name, setName] = useState("")
  const [email, setEmail] = useState("")
  const [password, setPassword] = useState("")
  const [role, setRole] = useState("employee")

  const [assetName, setAssetName] =
    useState("")

  const [assetCategory, setAssetCategory] =
    useState("")

  const [serialNumber, setSerialNumber] =
    useState("")

  const [assetStatus, setAssetStatus] =
    useState("active")

  const [assignedTo, setAssignedTo] =
    useState("")

  const [requestEmployee, setRequestEmployee] =
    useState("")

  const [requestAsset, setRequestAsset] =
    useState("")

  const [requestQuantity, setRequestQuantity] =
    useState(1)

  const [search, setSearch] = useState("")
  const [filterRole, setFilterRole] =
    useState("all")

  const fetchEmployees = async () => {
    try {
      const token = Cookies.get("token")

      const response = await axios.get(
        "http://localhost:5000/api/employees",
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      )

      setEmployees(response.data.employees)
    } catch (error) {
      console.log(error)
    }
  }

  const fetchAuditLogs = async () => {
    try {
      const token = Cookies.get("token")

      const response = await axios.get(
        "http://localhost:5000/api/audit-logs",
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      )

      setLogs(response.data.logs)
    } catch (error) {
      console.log(error)
    }
  }

  const fetchAssets = async () => {
    try {
      const token = Cookies.get("token")

      const response = await axios.get(
        "http://localhost:5000/api/assets",
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      )

      setAssets(response.data.assets)
    } catch (error) {
      console.log(error)
    }
  }

  const fetchRequests = async () => {
    try {
      const token = Cookies.get("token")

      const response = await axios.get(
        "http://localhost:5000/api/asset-requests",
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      )

      setRequests(response.data.requests)
    } catch (error) {
      console.log(error)
    }
  }

  const createEmployee = async () => {
    try {
      const token = Cookies.get("token")

      await axios.post(
        "http://localhost:5000/api/employees",
        {
          name,
          email,
          password,
          role,
        },
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      )

      alert("Employee created")

      setName("")
      setEmail("")
      setPassword("")
      setRole("employee")

      fetchEmployees()
      fetchAuditLogs()
    } catch (error) {
      console.log(error)

      alert("Failed to create employee")
    }
  }

  const createAsset = async () => {
    try {
      const token = Cookies.get("token")

      await axios.post(
        "http://localhost:5000/api/assets",
        {
          name: assetName,
          category: assetCategory,
          serialNumber,
          status: assetStatus,
          assignedTo,
        },
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      )

      alert("Asset created")

      setAssetName("")
      setAssetCategory("")
      setSerialNumber("")
      setAssetStatus("active")
      setAssignedTo("")

      fetchAssets()
      fetchAuditLogs()
    } catch (error) {
      console.log(error)

      alert("Failed to create asset")
    }
  }

  const createRequest = async () => {
    try {
      const token = Cookies.get("token")

      await axios.post(
        "http://localhost:5000/api/asset-requests",
        {
          employeeName: requestEmployee,
          assetName: requestAsset,
          quantity: requestQuantity,
        },
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      )

      alert("Request created")

      setRequestEmployee("")
      setRequestAsset("")
      setRequestQuantity(1)

      fetchRequests()
      fetchAuditLogs()
    } catch (error) {
      console.log(error)

      alert("Failed to create request")
    }
  }

  const approveRequest = async (
    id: string
  ) => {
    try {
      const token = Cookies.get("token")

      await axios.put(
        `http://localhost:5000/api/asset-requests/${id}/approve`,
        {},
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      )

      alert("Request approved")

      fetchRequests()
      fetchAuditLogs()
    } catch (error) {
      console.log(error)

      alert("Failed to approve")
    }
  }

  const deleteEmployee = async (id: string) => {
    try {
      const token = Cookies.get("token")

      await axios.delete(
        `http://localhost:5000/api/employees/${id}`,
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      )

      alert("Employee deleted")

      fetchEmployees()
      fetchAuditLogs()
    } catch (error) {
      console.log(error)

      alert("Failed to delete employee")
    }
  }

  const updateRole = async (
    id: string,
    role: string
  ) => {
    try {
      const token = Cookies.get("token")

      await axios.put(
        `http://localhost:5000/api/employees/${id}`,
        {
          role,
        },
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      )

      fetchEmployees()
      fetchAuditLogs()
    } catch (error) {
      console.log(error)
    }
  }


  useEffect(() => {
    fetchEmployees()
    fetchAuditLogs()
    fetchAssets()
    fetchRequests()
  }, [])

  return (
    <div className="min-h-screen bg-gray-100">
      <div className="flex">

        <Sidebar />

        <main className="flex-1 p-10">

          <h1 className="text-4xl font-bold mb-2">
            HRGA Dashboard
          </h1>

          <p className="text-gray-500 mb-8">
            Enterprise Management System
          </p>

          <DashboardCards
  employees={employees}
  assets={assets}
  requests={requests}
  logs={logs}
/>

          <div className="grid grid-cols-2 gap-6 mb-10">

            <div className="bg-white p-6 rounded-2xl shadow">

              <h2 className="text-2xl font-bold mb-6">
                Create Employee
              </h2>

              <div className="space-y-4">

                <input
                  className="border p-3 rounded-lg w-full"
                  placeholder="Name"
                  value={name}
                  onChange={(e) =>
                    setName(e.target.value)
                  }
                />

                <input
                  className="border p-3 rounded-lg w-full"
                  placeholder="Email"
                  value={email}
                  onChange={(e) =>
                    setEmail(e.target.value)
                  }
                />

                <input
                  type="password"
                  className="border p-3 rounded-lg w-full"
                  placeholder="Password"
                  value={password}
                  onChange={(e) =>
                    setPassword(e.target.value)
                  }
                />

                <select
                  className="border p-3 rounded-lg w-full"
                  value={role}
                  onChange={(e) =>
                    setRole(e.target.value)
                  }
                >
                  <option value="employee">
                    Employee
                  </option>

                  <option value="hr">
                    HR
                  </option>

                  <option value="admin">
                    Admin
                  </option>
                </select>

                <button
                  className="bg-black text-white px-6 py-3 rounded-lg w-full"
                  onClick={createEmployee}
                >
                  Create Employee
                </button>

              </div>

            </div>

            <div className="bg-white p-6 rounded-2xl shadow">

              <h2 className="text-2xl font-bold mb-6">
                Create Asset
              </h2>

              <div className="space-y-4">

                <input
                  className="border p-3 rounded-lg w-full"
                  placeholder="Asset Name"
                  value={assetName}
                  onChange={(e) =>
                    setAssetName(e.target.value)
                  }
                />

                <input
                  className="border p-3 rounded-lg w-full"
                  placeholder="Category"
                  value={assetCategory}
                  onChange={(e) =>
                    setAssetCategory(e.target.value)
                  }
                />

                <input
                  className="border p-3 rounded-lg w-full"
                  placeholder="Serial Number"
                  value={serialNumber}
                  onChange={(e) =>
                    setSerialNumber(e.target.value)
                  }
                />

                <input
                  className="border p-3 rounded-lg w-full"
                  placeholder="Assigned To"
                  value={assignedTo}
                  onChange={(e) =>
                    setAssignedTo(e.target.value)
                  }
                />

                <button
                  className="bg-black text-white px-6 py-3 rounded-lg w-full"
                  onClick={createAsset}
                >
                  Create Asset
                </button>

              </div>

            </div>

          </div>

          <div className="bg-white p-6 rounded-2xl shadow mb-10">

            <h2 className="text-2xl font-bold mb-6">
              Request Asset
            </h2>

            <div className="grid grid-cols-3 gap-4">

              <input
                className="border p-3 rounded-lg"
                placeholder="Employee Name"
                value={requestEmployee}
                onChange={(e) =>
                  setRequestEmployee(
                    e.target.value
                  )
                }
              />

              <input
                className="border p-3 rounded-lg"
                placeholder="Asset Name"
                value={requestAsset}
                onChange={(e) =>
                  setRequestAsset(
                    e.target.value
                  )
                }
              />

              <input
                type="number"
                className="border p-3 rounded-lg"
                placeholder="Quantity"
                value={requestQuantity}
                onChange={(e) =>
                  setRequestQuantity(
                    Number(e.target.value)
                  )
                }
              />

            </div>

            <button
              className="mt-5 bg-black text-white px-6 py-3 rounded-lg"
              onClick={createRequest}
            >
              Create Request
            </button>

          </div>

          <EmployeeTable
  employees={employees}
  search={search}
  setSearch={setSearch}
  filterRole={filterRole}
  setFilterRole={setFilterRole}
/>

          <AssetTable assets={assets} />

          <div className="bg-white rounded-2xl shadow overflow-hidden p-6 mb-10">

            <h2 className="text-2xl font-bold mb-6">
              Asset Requests
            </h2>

            <table className="w-full">

              <thead className="bg-gray-100">

                <tr>

                  <th className="text-left p-4">
                    Employee
                  </th>

                  <th className="text-left p-4">
                    Asset
                  </th>

                  <th className="text-left p-4">
                    Quantity
                  </th>

                  <th className="text-left p-4">
                    Status
                  </th>

                  <th className="text-left p-4">
                    Actions
                  </th>

                </tr>

              </thead>

              <tbody>

                {requests.map((request: any) => (
                  <tr
                    key={request.id}
                    className="border-t hover:bg-gray-50"
                  >

                    <td className="p-4">
                      {request.employeeName}
                    </td>

                    <td className="p-4">
                      {request.assetName}
                    </td>

                    <td className="p-4">
                      {request.quantity}
                    </td>

                    <td className="p-4 uppercase">
                      {request.status}
                    </td>

                    <td className="p-4">

                      {request.status ===
                      "pending" ? (
                        <button
                          className="bg-green-500 hover:bg-green-600 text-white px-4 py-2 rounded-lg"
                          onClick={() =>
                            approveRequest(
                              request.id
                            )
                          }
                        >
                          Approve
                        </button>
                      ) : (
                        <span className="text-green-600 font-semibold">
                          Approved
                        </span>
                      )}

                    </td>

                  </tr>
                ))}

              </tbody>

            </table>

          </div>

          <div className="bg-white rounded-2xl shadow overflow-hidden p-6">

            <h2 className="text-2xl font-bold mb-6">
              Audit Logs
            </h2>

            <table className="w-full">

              <thead className="bg-gray-100">

                <tr>

                  <th className="text-left p-4">
                    Action
                  </th>

                  <th className="text-left p-4">
                    Actor
                  </th>

                  <th className="text-left p-4">
                    Target ID
                  </th>

                  <th className="text-left p-4">
                    Time
                  </th>

                </tr>

              </thead>

              <tbody>

                {logs.map((log: any) => (
                  <tr
                    key={log.id}
                    className="border-t hover:bg-gray-50"
                  >

                    <td className="p-4 font-semibold">
                      {log.action}
                    </td>

                    <td className="p-4">
                      {log.actorId}
                    </td>

                    <td className="p-4 text-sm">
                      {log.targetId}
                    </td>

                    <td className="p-4">
                      {new Date(
                        log.createdAt
                      ).toLocaleString()}
                    </td>

                  </tr>
                ))}

              </tbody>

            </table>

          </div>

        </main>
      </div>
    </div>
  )
}